import{_ as t,o as e,c as s,S as i}from"./chunks/framework.C6RQlTYc.js";const A=JSON.parse('{"title":"面试官问：什么是 AI？弱 AI、强 AI、超级 AI 有什么区别？","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_1-what_is_ai.md","filePath":"面试官问/17ai/q_ai_1-what_is_ai.md","lastUpdated":1778207238000}'),n={name:"面试官问/17ai/q_ai_1-what_is_ai.md"};function r(l,a,d,o,p,h){return e(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="面试官问-什么是-ai-弱-ai、强-ai、超级-ai-有什么区别" tabindex="-1">面试官问：什么是 AI？弱 AI、强 AI、超级 AI 有什么区别？ <a class="header-anchor" href="#面试官问-什么是-ai-弱-ai、强-ai、超级-ai-有什么区别" aria-label="Permalink to &quot;面试官问：什么是 AI？弱 AI、强 AI、超级 AI 有什么区别？&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_1-what_is_ai.html">什么是 AI</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_5-generative_ai.html">生成式 AI</a></p></blockquote><p><strong>考察点</strong>：AI 三个能力层级（ANI → AGI → ASI）的区分、当前技术所处阶段、AI 发展的关键里程碑</p><details class="details custom-block"><summary>详细信息</summary><h2 id="核心回答" tabindex="-1">核心回答 <a class="header-anchor" href="#核心回答" aria-label="Permalink to &quot;核心回答&quot;">​</a></h2><p>AI（人工智能）是让机器模拟人类智能行为的科学。按能力层级分为三种：</p><table><thead><tr><th>层级</th><th>英文</th><th>能力</th><th style="text-align:center;">现状</th></tr></thead><tbody><tr><td><strong>弱 AI (ANI)</strong></td><td>Narrow AI</td><td>单一任务超越人类</td><td style="text-align:center;">✅ 已实现（如 GPT、AlphaGo）</td></tr><tr><td><strong>强 AI (AGI)</strong></td><td>General AI</td><td>达到人类水平的通用智能</td><td style="text-align:center;">❌ 未实现</td></tr><tr><td><strong>超级 AI (ASI)</strong></td><td>Super AI</td><td>全面超越人类</td><td style="text-align:center;">❌ 仅存于理论</td></tr></tbody></table><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>AI 三大流派：</span></span>
<span class="line"><span>├── 符号主义：逻辑推理，专家系统（早期主流）</span></span>
<span class="line"><span>├── 连接主义：神经网络，深度学习（当前主流）</span></span>
<span class="line"><span>└── 行为主义：强化学习，与环境交互</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>关键里程碑</strong>：1956 达特茅斯会议（诞生）→ 1997 深蓝 → 2012 AlexNet → 2016 AlphaGo → 2017 Transformer → 2023 GPT-4</p><h2 id="面试回答要点" tabindex="-1">面试回答要点 <a class="header-anchor" href="#面试回答要点" aria-label="Permalink to &quot;面试回答要点&quot;">​</a></h2><ul><li>区分三个层级，给出具体例子</li><li>知道当前是 ANI 时代，AGI 仍未实现</li><li>能说出 2017 Transformer 是转折点</li></ul></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_1-what_is_ai.html">什么是 AI 概念讲解</a></p></blockquote>`,5)])])}const _=t(n,[["render",r]]);export{A as __pageData,_ as default};
